import{apiUrl,CONFIG}from"../utils/config.js";import{getSession}from"../utils/storage.js";export async function startStripeCheckout(t){const o=await fetch(apiUrl(CONFIG.endpoints.stripeCheckout),{method:"POST",headers:{"Content-Type":"application/json",Authorization:`Bearer ${getSession()?.token||"guest"}`},body:JSON.stringify({plan:t})});if(!o.ok)throw new Error(await o.text());const i=await o.json();window.location.href=i.url}